function createNegotiationState(supplierId: SupplierId): NegotiationState {
  const supplier = getSupplier(supplierId);
  return {
    supplierId,
    round: 1,
    currentPrice: supplier.initialPrice,
    terms: supplier.initialTerms,
    warranty: supplier.initialWarranty,
    mood: 72,
    hardlineCount: 0,
    freightTrapTriggered: false,
    done: false,
    log: [],
  };
}

function getSupplier(supplierId: SupplierId) {
  return NEGOTIATION_SUPPLIERS.find((item) => item.id === supplierId) ?? NEGOTIATION_SUPPLIERS[0];
}

function money(value: number) {
  return `¥${value.toLocaleString("zh-CN")}`;
}

function quantity(value: string) {
  return Number(value) || 0;
}

function scoreSourcing(selectedIds: string[]) {
  const correct = selectedIds.filter((id) => CANDIDATES.find((item) => item.id === id)?.eligible).length;
  return correct === 3 ? 100 : correct === 2 ? 60 : correct === 1 ? 20 : 0;
}

function scoreNegotiation(state: NegotiationState) {
  const supplier = getSupplier(state.supplierId);
  const priceScore = Math.min(
    60,
    Math.max(0, ((supplier.initialPrice - state.currentPrice) / supplier.maxDrop) * 60),
  );
  const termsScore = state.terms === supplier.targetTerms ? 20 : 0;
  const warrantyScore = state.warranty >= supplier.targetWarranty ? 20 : 0;
  return Math.round(priceScore + termsScore + warrantyScore);
}

function getComment(score: number, freightTrapTriggered: boolean) {
  const freightNote = freightTrapTriggered
    ? " 但你触发了运费陷阱，需要把单价之外的综合到手成本纳入判断。"
    : "";
  if (score >= 85) return `谈判策略运用得当，价格、账期、质保均取得明显改善，综合成本控制优秀。${freightNote}`;
  if (score >= 65) return `谈判有一定成效，但部分条款仍有空间未争取到，建议复盘哪些轮次降低了供应商配合意愿。${freightNote}`;
  if (score >= 40) return `策略偏单一，供应商让步有限。注意一味施压或强硬会降低供应商态度，导致条款谈判失败。${freightNote}`;
  return `谈判结果不理想，建议重新梳理策略组合，再试一次。${freightNote}`;
}

function applyNegotiationChoice(state: NegotiationState, strategy: Strategy): NegotiationState {
  const supplier = getSupplier(state.supplierId);
  const round = state.round;
  const hardlineCount = state.hardlineCount + (strategy === "hard" ? 1 : 0);
  let nextPrice = state.currentPrice;
  let nextTerms = state.terms;
  let nextWarranty = state.warranty;
  let nextMood = state.mood;
  let freightTrapTriggered = state.freightTrapTriggered;
  let response = "";
  let delta = "条款保持";

  const dropBy = (amount: number) => {
    const before = nextPrice;
    nextPrice = Math.max(supplier.floorPrice, nextPrice - amount);
    delta = before === nextPrice ? "价格触底" : `降价 ${money(before - nextPrice)}`;
  };

  if (strategy === "press") {
    dropBy(supplier.id === "youxian" ? 300 : 500);
    nextMood -= 8;
    response = "我们理解你们的压力，可以再释放一点价格空间，但希望保留合理利润。";
  }

  if (strategy === "bundle") {
    dropBy(supplier.id === "youxian" ? 350 : 650);
    nextMood += 6;
    response = "长期合作对我们有吸引力，这单可以拿出更有诚意的价格。";
  }

  if (strategy === "trade") {
    if (round <= 2) {
      nextTerms = supplier.targetTerms;
      dropBy(supplier.id === "youxian" ? 0 : 250);
      response = `账期可以调整为${supplier.targetTerms}，价格暂时按当前方案推进。`;
      delta = `账期升级为${supplier.targetTerms}`;
    } else {
      nextWarranty = supplier.targetWarranty;
      response = `质保 ${supplier.targetWarranty} 个月可以配合，我们对产品稳定性有信心。`;
      delta = `质保升级为 ${supplier.targetWarranty} 个月`;
    }
    nextMood += 4;
  }

  if (strategy === "hard") {
    dropBy(supplier.id === "youxian" ? 250 : 700);
    nextMood -= 16;
    response = "这是我们能给出的底线附近了，再低会影响供货稳定性。";
  }

  if (supplier.id === "shengfeng" && hardlineCount >= 2) {
    freightTrapTriggered = true;
    nextPrice = Math.max(supplier.floorPrice, nextPrice);
    response = "好，¥27,000 我们咬牙接。但运费需要单独核算，天津到贵司约 ¥800/吨。";
    delta = "触发运费陷阱";
  }

  const nextRound = round + 1;

  return {
    ...state,
    round: Math.min(5, nextRound),
    currentPrice: nextPrice,
    terms: nextTerms,
    warranty: nextWarranty,
    mood: Math.max(0, Math.min(100, nextMood)),
    hardlineCount,
    freightTrapTriggered,
    done: round >= 5,
    log: [
      ...state.log,
      {
        round,
        strategy,
        response,
        price: nextPrice,
        delta,
      },
    ],
  };
}

export default function TrainingPage() {
  const { isAuthenticated, isAuthReady, openAuthModal } = useAuth();
  const [activeCaseId, setActiveCaseId] = useState<TrainingCaseId>("jam");
  const [activeStep, setActiveStep] = useState<StepId>(1);
  const [selectedCandidates, setSelectedCandidates] = useState<string[]>([]);
  const [sourcingScore, setSourcingScore] = useState<number | null>(null);
  const [negotiation, setNegotiation] = useState<NegotiationState>(() => createNegotiationState("shengfeng"));
  const [purchaseQuote, setPurchaseQuote] = useState<PurchaseQuote>(DEFAULT_QUOTE);

  const negotiationSupplier = getSupplier(negotiation.supplierId);
  const negotiationScore = useMemo(() => scoreNegotiation(negotiation), [negotiation]);
  const actualCost = negotiation.freightTrapTriggered ? negotiation.currentPrice + 800 : negotiation.currentPrice;
  const isQuoteComplete = [
    purchaseQuote.category,
    purchaseQuote.itemName,
    purchaseQuote.spec,
    purchaseQuote.annualQuantity,
    purchaseQuote.deliveryCycle,
    purchaseQuote.quoteValidity,
  ].every((value) => value.trim().length > 0);
  const quoteTotal = actualCost * quantity(purchaseQuote.annualQuantity);
  const completedSteps = [
    activeStep > 1,
    sourcingScore !== null,
    negotiation.done,
    activeStep > 4 && isQuoteComplete,
    activeStep === 5,
  ].filter(Boolean).length;
  const activeCase = TRAINING_CASES.find((item) => item.id === activeCaseId) ?? TRAINING_CASES[0];
  const completedCaseIds = new Set<TrainingCaseId>(negotiation.done && isQuoteComplete && activeStep === 5 ? ["jam"] : []);

  const requireAuth = () => {
    openAuthModal({ mode: "login", reason: "进入果酱采购实训前，请先登录学习账号。" });
  };

  const submitDemand = () => {
    setActiveStep(2);
  };

  const toggleCandidate = (id: string) => {
    setSelectedCandidates((current) => {
      if (current.includes(id)) return current.filter((item) => item !== id);
      if (current.length >= 3) return current;
      return [...current, id];
    });
  };

  const submitSourcing = () => {
    if (selectedCandidates.length !== 3) return;
    setSourcingScore(scoreSourcing(selectedCandidates));
    setActiveStep(3);
  };

  const selectNegotiationSupplier = (supplierId: SupplierId) => {
    setNegotiation(createNegotiationState(supplierId));
  };

  const chooseStrategy = (strategy: Strategy) => {
    setNegotiation((current) => {
      if (current.done) return current;
      const next = applyNegotiationChoice(current, strategy);
      if (next.done) setActiveStep(4);
      return next;
    });
  };

  const updatePurchaseQuote = <K extends keyof PurchaseQuote>(key: K, value: PurchaseQuote[K]) => {
    setPurchaseQuote((current) => ({
      ...current,
      [key]: value,
    }));
  };

  const submitPurchaseQuote = () => {
    if (!isQuoteComplete) return;
    setActiveStep(5);
  };

  const isCaseUnlocked = (caseId: TrainingCaseId) => {
    const index = TRAINING_CASES.findIndex((item) => item.id === caseId);
    if (index <= 0) return true;
    return completedCaseIds.has(TRAINING_CASES[index - 1].id);
  };

  if (isAuthReady && !isAuthenticated) {
    return (
      <section className="jam-training-page">
        <div className="jam-lock-panel">
          <div className="eyebrow">Training Case</div>
          <h2 className="page-title">草莓果酱采购寻源实训</h2>
          <p className="page-description">
            本案例包含需求分析、市场寻源、商务谈判、采购报价单和决策复盘。登录后会记录你的实训过程。
          </p>
          <button className="button-primary" type="button" onClick={requireAuth}>
            登录后开始实训
          </button>
        </div>
      </section>
    );
  }

  return (
    <section className="jam-training-page">
      <header className="jam-training-head">
        <div>
          <div className="eyebrow">Jam Sourcing Simulation</div>
          <h2 className="page-title">{activeCase.title}</h2>
          <p className="page-description">
            {activeCase.id === "jam"
              ? "年采购 200 吨草莓果酱，用五步完成采购规格、入围筛选、商务谈判、报价单填写和系统复盘。"
              : activeCase.subtitle}
          </p>
        </div>
        <div className="jam-case-metrics">
          <div><span>流程</span><b>{activeCase.steps} 步</b></div>
          <div><span>谈判</span><b>{activeCase.isImplemented ? `${negotiation.round}/5` : "--"}</b></div>
          <div><span>得分</span><b>{activeCase.isImplemented && negotiation.done ? `${negotiationScore}/100` : "--"}</b></div>
        </div>
      </header>

      <nav className="jam-stepper" aria-label="实训步骤">
        {STEPS.map((step) => (
          <button
            key={step.id}
            className={`jam-step${activeStep === step.id ? " is-current" : ""}${activeStep > step.id ? " is-complete" : ""}`}
            type="button"
            onClick={() => setActiveStep(step.id)}
          >
            <span className="jam-step-icon">{step.id}</span>
            <span>
              <small>STEP {String(step.id).padStart(2, "0")}</small>
              <b>{step.title}</b>
              <em>{step.subtitle}</em>
            </span>
          </button>
        ))}
      </nav>

      <div className="jam-workspace">
        <aside className="jam-rail" aria-label="实训案例">
          <div className="jam-case-switch-head">
            <div>
              <span>TRAINING CASES</span>
              <strong>案例切换</strong>
            </div>
            <em>{TRAINING_CASES.length} 个案例</em>
          </div>

          <div className="jam-case-switch-list">
            {TRAINING_CASES.map((caseItem) => {
              const unlocked = isCaseUnlocked(caseItem.id);
              const complete = completedCaseIds.has(caseItem.id);
              const active = activeCaseId === caseItem.id;

              return (
                <button
                  key={caseItem.id}
                  type="button"
                  className={`jam-case-switch-card${active ? " is-active" : ""}${complete ? " is-complete" : ""}`}
                  disabled={!unlocked}
                  onClick={() => {
                    if (unlocked) {
                      setActiveCaseId(caseItem.id);
                    }
                  }}
                >
                  <span className="jam-case-switch-index">
                    {String(caseItem.order).padStart(2, "0")}
                  </span>
                  <span className="jam-case-switch-body">
                    <b>{caseItem.title}</b>
                    <em>{caseItem.subtitle}</em>
                    <small>
                      {complete
                        ? "已完成"
                        : unlocked
                          ? caseItem.isImplemented
                            ? `${caseItem.steps} 步实训`
                            : "已解锁，待配置"
                          : "完成上一个案例后解锁"}
                    </small>
                  </span>
                </button>
              );
            })}
          </div>
        </aside>

        <main className="jam-main">
          {!activeCase.isImplemented ? (
            <section className="jam-step-view">
              <div className="jam-section-head">
                <div>
                  <div className="eyebrow">Case {String(activeCase.order).padStart(2, "0")}</div>
                  <h3 className="section-title">{activeCase.title}</h3>
                </div>
                <span className="jam-score-chip">待配置</span>
              </div>
              <div className="jam-empty">
                该案例已经满足解锁条件，但内容配置还没有接入。当前可继续查看或重做草莓果酱案例。
              </div>
            </section>
          ) : activeStep === 1 ? (
            <section className="jam-step-view">
              <div className="jam-section-head">
                <div>
                  <div className="eyebrow">Step 01</div>
                  <h3 className="section-title">需求分析 · 阅读案例说明</h3>
                </div>
                <span className="jam-score-chip">CASE BRIEF</span>
              </div>

              <div className="jam-case-intro-grid">
                <article className="jam-procurement-doc">
                  <div className="jam-doc-head">
                    <div>
                      <span>PROCUREMENT BRIEF</span>
                      <strong>内部采购需求说明</strong>
                    </div>
                    <span>CONFIDENTIAL</span>
                  </div>
                  <p>{DEMAND_TEXT}</p>
                </article>

                <figure className="jam-case-figure">
                  <img src={CASE_IMAGE_URL} alt="草莓拿铁夹心饼干产品场景" />
                </figure>
              </div>
            </section>
          ) : null}

          {activeStep === 2 ? (
            <section className="jam-step-view">
              <div className="jam-section-head">
                <div>
                  <div className="eyebrow">Step 02</div>
                  <h3 className="section-title">市场寻源 · 从 6 家候选供应商中选择 3 家入围</h3>
                </div>
                <span className="jam-score-chip">{selectedCandidates.length} / 3 已选</span>
              </div>

              <div className="jam-supplier-grid">
                {CANDIDATES.map((supplier) => {
                  const picked = selectedCandidates.includes(supplier.id);
                  return (
                    <button
                      key={supplier.id}
                      className={`jam-supplier-card${picked ? " is-picked" : ""}`}
                      type="button"
                      onClick={() => toggleCandidate(supplier.id)}
                    >
                      <span className="jam-supplier-code">{supplier.code}{picked ? " · 入围" : ""}</span>
                      <strong>{supplier.name}</strong>
                      <dl>
                        <div><dt>地点</dt><dd>{supplier.location}</dd></div>
                        <div><dt>认证</dt><dd>{supplier.certifications}</dd></div>
                        <div><dt>产能</dt><dd>{supplier.capacity}</dd></div>
                        <div><dt>报价</dt><dd>{supplier.quote}</dd></div>
                      </dl>
                      <p>{supplier.note}</p>
                    </button>
                  );
                })}
              </div>

              {sourcingScore !== null ? (
                <div className="jam-notification">
                  <b>寻源评分：{sourcingScore} / 100</b>
                  <span>
                    标准入围组合为 A 锐达、C 优鲜源、F 盛丰。B/D 认证不满足双证要求，E 有糖度投诉风险。
                  </span>
                </div>
              ) : null}
            </section>
          ) : null}

          {activeStep === 3 ? (
            <section className="jam-step-view">
              <div className="jam-section-head">
                <div>
                  <div className="eyebrow">Step 03</div>
                  <h3 className="section-title">商务谈判 · 选择一家入围供应商完成 5 轮谈判</h3>
                </div>
                <span className="jam-score-chip">Round {negotiation.round} / 5</span>
              </div>

              <div className="jam-negotiation-tabs">
                {NEGOTIATION_SUPPLIERS.map((supplier) => (
                  <button
                    key={supplier.id}
                    className={supplier.id === negotiation.supplierId ? "is-active" : ""}
                    type="button"
                    onClick={() => selectNegotiationSupplier(supplier.id)}
                  >
                    <span>{supplier.code}</span>
                    <b>{supplier.name}</b>
                    <em>{supplier.role} · 起价 {money(supplier.initialPrice)}</em>
                  </button>
                ))}
              </div>

              <article className="jam-negotiation-stage">
                <div className="jam-stage-head">
                  <div className="jam-avatar">{negotiationSupplier.code}</div>
                  <div>
                    <strong>{negotiationSupplier.name}</strong>
                    <span>{negotiationSupplier.role} · 谈判中</span>
                  </div>
                  <div className="jam-round-pill">回合 {negotiation.round} / 5</div>
                </div>

                <div className="jam-speech">
                  {negotiation.log.at(-1)?.response ??
                    `当前报价 ${money(negotiation.currentPrice)} / 吨。请从四种策略中选择你的下一轮话术。`}
                </div>

                <div className="jam-options">
                  {(Object.keys(STRATEGY_LABEL) as Strategy[]).map((strategy) => (
                    <button
                      key={strategy}
                      type="button"
                      disabled={negotiation.done}
                      onClick={() => chooseStrategy(strategy)}
                    >
                      <span>{STRATEGY_LABEL[strategy]}</span>
                      <b>{ROUND_OPTIONS[negotiation.round]?.[strategy] ?? ROUND_OPTIONS[5][strategy]}</b>
                      <em>{STRATEGY_HINT[strategy]}</em>
                    </button>
                  ))}
                </div>
              </article>

              <article className="jam-negotiation-log">
                <div className="jam-log-row is-head">
                  <span>回合</span><span>策略</span><span>对方回应</span><span>报价</span><span>变化</span>
                </div>
                {negotiation.log.length === 0 ? (
                  <div className="jam-empty">尚未开始谈判。</div>
                ) : (
                  negotiation.log.map((item) => (
                    <div key={item.round} className="jam-log-row">
                      <span>R{item.round}</span>
                      <span>{STRATEGY_LABEL[item.strategy]}</span>
                      <span>{item.response}</span>
                      <span>{money(item.price)}</span>
                      <span>{item.delta}</span>
                    </div>
                  ))
                )}
              </article>
            </section>
          ) : null}

          {activeStep === 4 ? (
            <section className="jam-step-view">
              <div className="jam-section-head">
                <div>
                  <div className="eyebrow">Step 04</div>
                  <h3 className="section-title">采购报价单 · 确认成交供应商与采购条款</h3>
                </div>
                <span className="jam-score-chip">QUOTE FORM</span>
              </div>

              <div className="jam-quotation-grid">
                <article className="jam-spec-form jam-quotation-form">
                  <div className="jam-spec-form-head">
                    <div>
                      <span>PROCUREMENT QUOTATION</span>
                      <strong>采购报价单</strong>
                    </div>
                    <em>草莓果酱寻源实训</em>
                  </div>

                  <div className="jam-spec-grid">
                    <label className="jam-field">
                      <span><b>采购品类</b><em>Category</em></span>
                      <select
                        value={purchaseQuote.category}
                        onChange={(event) => updatePurchaseQuote("category", event.target.value)}
                      >
                        <option value="食品原料">食品原料</option>
                        <option value="包装材料">包装材料</option>
                        <option value="工业品">工业品</option>
                        <option value="办公耗材">办公耗材</option>
                      </select>
                    </label>

                    <label className="jam-field">
                      <span><b>物料名称</b><em>Item</em></span>
                      <input
                        value={purchaseQuote.itemName}
                        onChange={(event) => updatePurchaseQuote("itemName", event.target.value)}
                      />
                    </label>

                    <label className="jam-field">
                      <span><b>年采购量</b><em>Qty</em></span>
                      <input
                        inputMode="numeric"
                        value={purchaseQuote.annualQuantity}
                        onChange={(event) => updatePurchaseQuote("annualQuantity", event.target.value)}
                      />
                    </label>

                    <label className="jam-field">
                      <span><b>计量单位</b><em>Unit</em></span>
                      <select
                        value={purchaseQuote.unit}
                        onChange={(event) => updatePurchaseQuote("unit", event.target.value)}
                      >
                        <option value="吨">吨</option>
                        <option value="千克">千克</option>
                        <option value="箱">箱</option>
                        <option value="件">件</option>
                      </select>
                    </label>

                    <label className="jam-field">
                      <span><b>交付要求</b><em>Lead time</em></span>
                      <input
                        value={purchaseQuote.deliveryCycle}
                        onChange={(event) => updatePurchaseQuote("deliveryCycle", event.target.value)}
                      />
                    </label>

                    <label className="jam-field">
                      <span><b>报价有效期</b><em>Validity</em></span>
                      <input
                        value={purchaseQuote.quoteValidity}
                        onChange={(event) => updatePurchaseQuote("quoteValidity", event.target.value)}
                      />
                    </label>

                    <label className="jam-field is-wide">
                      <span><b>规格要求</b><em>Specification</em></span>
                      <textarea
                        value={purchaseQuote.spec}
                        onChange={(event) => updatePurchaseQuote("spec", event.target.value)}
                      />
                    </label>

                    <label className="jam-field is-wide">
                      <span><b>备注</b><em>Remarks</em></span>
                      <textarea
                        value={purchaseQuote.remarks}
                        onChange={(event) => updatePurchaseQuote("remarks", event.target.value)}
                      />
                    </label>
                  </div>
                </article>

                <aside className="jam-quotation-summary">
                  <div className="jam-spec-form-head">
                    <div>
                      <span>FINAL TERMS</span>
                      <strong>谈判结果带入</strong>
                    </div>
                    <em>自动生成</em>
                  </div>

                  <dl className="jam-summary-list">
                    <div><dt>成交供应商</dt><dd>{negotiationSupplier.name}</dd></div>
                    <div><dt>采购品类</dt><dd>{purchaseQuote.category || "待填写"}</dd></div>
                    <div><dt>成交单价</dt><dd>{money(actualCost)} / {purchaseQuote.unit || "吨"}</dd></div>
                    <div><dt>采购数量</dt><dd>{purchaseQuote.annualQuantity || "--"} {purchaseQuote.unit}</dd></div>
                    <div><dt>预估总额</dt><dd>{quoteTotal ? money(quoteTotal) : "--"}</dd></div>
                    <div><dt>税运方式</dt><dd>{purchaseQuote.taxMode}</dd></div>
                    <div><dt>付款账期</dt><dd>{negotiation.terms}</dd></div>
                    <div><dt>质保周期</dt><dd>{negotiation.warranty} 个月</dd></div>
                    {negotiation.freightTrapTriggered ? (
                      <div className="is-warn"><dt>风险提示</dt><dd>谈判中触发了运费单独核算，报价单已按综合到手成本展示。</dd></div>
                    ) : null}
                  </dl>

                  <div className="jam-notification">
                    <b>{isQuoteComplete ? "报价单信息已完整" : "请补齐报价单必填信息"}</b>
                    <span>品类、物料、规格、数量、交付要求和报价有效期会作为进入复盘的必要信息。</span>
                  </div>
                </aside>
              </div>
            </section>
          ) : null}

          {activeStep === 5 ? (
            <section className="jam-step-view">
              <div className="jam-section-head">
                <div>
                  <div className="eyebrow">Step 05</div>
                  <h3 className="section-title">决策复盘 · 谈判结果与系统点评</h3>
                </div>
                <span className="jam-score-chip">{negotiationScore} / 100</span>
              </div>

              <div className="jam-report-grid">
                <article className="jam-report-tile">
                  <span>谈判得分</span>
                  <strong>{negotiationScore}<small> / 100</small></strong>
                  <p>{getComment(negotiationScore, negotiation.freightTrapTriggered)}</p>
                </article>

                <article className="jam-report-tile">
                  <span>最终条款</span>
                  <dl className="jam-summary-list">
                    <div><dt>谈判对象</dt><dd>{negotiationSupplier.name}</dd></div>
                    <div><dt>采购品类</dt><dd>{purchaseQuote.category}</dd></div>
                    <div><dt>采购物料</dt><dd>{purchaseQuote.itemName}</dd></div>
                    <div><dt>成交单价</dt><dd>{money(negotiation.currentPrice)} / 吨</dd></div>
                    <div><dt>预估总额</dt><dd>{quoteTotal ? money(quoteTotal) : "--"}</dd></div>
                    <div><dt>账期</dt><dd>{negotiation.terms}</dd></div>
                    <div><dt>质保</dt><dd>{negotiation.warranty} 个月</dd></div>
                    {negotiation.freightTrapTriggered ? (
                      <div className="is-warn"><dt>综合到手</dt><dd>{money(actualCost)} / 吨（含运费陷阱）</dd></div>
                    ) : null}
                  </dl>
                </article>

                <article className="jam-report-tile is-wide">
                  <span>评分拆解</span>
                  <div className="jam-breakdown">
                    <div><b>价格节省</b><span><i style={{ width: `${Math.min(100, ((negotiationSupplier.initialPrice - negotiation.currentPrice) / negotiationSupplier.maxDrop) * 100)}%` }} /></span><em>60 分上限</em></div>
                    <div><b>账期改善</b><span><i style={{ width: negotiation.terms === negotiationSupplier.targetTerms ? "100%" : "0%" }} /></span><em>20 分</em></div>
                    <div><b>质保改善</b><span><i style={{ width: negotiation.warranty >= negotiationSupplier.targetWarranty ? "100%" : "0%" }} /></span><em>20 分</em></div>
                  </div>
                </article>
              </div>
            </section>
          ) : null}
        </main>
      </div>

      <footer className="jam-action-bar">
        <div className="jam-progress-text">已完成 <b>{completedSteps} / 5</b> 步</div>
        <div className="jam-footer-actions">
          {!activeCase.isImplemented ? (
            <button className="button-primary" type="button" onClick={() => setActiveCaseId("jam")}>
              返回草莓果酱案例
            </button>
          ) : (
            <>
              <button
                className="button-secondary"
                type="button"
                disabled={activeStep <= 1}
                onClick={() => setActiveStep((current) => Math.max(1, current - 1) as StepId)}
              >
                上一步
              </button>
              {activeStep === 1 ? (
                <button className="button-primary" type="button" onClick={submitDemand}>
                  已阅读，进入市场寻源
                </button>
              ) : null}
              {activeStep === 2 ? (
                <button
                  className="button-primary"
                  type="button"
                  disabled={selectedCandidates.length !== 3}
                  onClick={submitSourcing}
                >
                  确认 3 家入围
                </button>
              ) : null}
              {activeStep === 3 ? (
                <button
                  className="button-primary"
                  type="button"
                  disabled={!negotiation.done}
                  onClick={() => setActiveStep(4)}
                >
                  填写采购报价单
                </button>
              ) : null}
              {activeStep === 4 ? (
                <button
                  className="button-primary"
                  type="button"
                  disabled={!isQuoteComplete}
                  onClick={submitPurchaseQuote}
                >
                  确认报价单，进入复盘
                </button>
              ) : null}
              {activeStep === 5 ? (
                <button className="button-primary" type="button" onClick={() => window.print()}>
                  导出复盘报告
                </button>
              ) : null}
            </>
          )}
        </div>
      </footer>
    </section>
  );
}
